#### TailwindConfig

```json
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "jet://schemas/tailwind-config",
  "type": "object",
  "properties": {
    "content": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Glob patterns for content scanning (e.g. ['./src/**/*.{ts,tsx}'])"
    },
    "darkMode": {
      "enum": ["class"],
      "description": "Dark mode strategy. Only 'class' is supported."
    },
    "theme": {
      "type": "object",
      "properties": {
        "extend": { "$ref": "#/$defs/ThemeExtend" }
      }
    },
    "plugins": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Plugin names: 'tailwindcss-animate', '@tailwindcss/typography'"
    }
  },
  "$defs": {
    "ThemeExtend": {
      "type": "object",
      "properties": {
        "colors": {
          "type": "object",
          "additionalProperties": { "type": "string" },
          "description": "Color extensions. Values may use hsl(var(--*)) pattern."
        },
        "fontFamily": {
          "type": "object",
          "additionalProperties": {
            "type": "array",
            "items": { "type": "string" }
          }
        },
        "spacing": {
          "type": "object",
          "additionalProperties": { "type": "string" }
        },
        "borderRadius": {
          "type": "object",
          "additionalProperties": { "type": "string" }
        }
      }
    }
  }
}
```

#### CssPipelineConfig

```json
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "jet://schemas/css-pipeline-config",
  "type": "object",
  "required": ["entry"],
  "properties": {
    "entry": {
      "type": "string",
      "description": "CSS entry point path (absolute or relative to project root)"
    },
    "minify": {
      "type": "boolean",
      "default": false,
      "description": "Enable lightningcss minification (set true for production)"
    },
    "source_map": {
      "type": "boolean",
      "default": false,
      "description": "Emit CSS source map"
    },
    "modules": {
      "type": "boolean",
      "default": false,
      "description": "Enable CSS Modules for .module.css files"
    },
    "tailwind": {
      "$ref": "jet://schemas/tailwind-config",
      "description": "Tailwind configuration (optional; loaded from tailwind.config.js if absent)"
    }
  }
}
```

#### CssOutput

```json
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "jet://schemas/css-output",
  "type": "object",
  "required": ["css", "hash"],
  "properties": {
    "css": {
      "type": "string",
      "description": "Final CSS string (transformed + optionally minified)"
    },
    "source_map": {
      "type": ["string", "null"],
      "description": "Inline or external CSS source map JSON (null if disabled)"
    },
    "hash": {
      "type": "string",
      "description": "SHA-256 content hash (first 8 hex chars) for cache-busting filename"
    }
  }
}
```
